import {
	NavBase as BaseClass,
} from "./NavBase";
import {
	Perspective,
	ProjectionBase as Projection,
} from "../Projections";
import {
	intersectLinePlane,
	intersectLineSphere,
	isFiniteNumber,
	Plane,
	Sphere,
	type ILineSphereIntersection,
} from "../Math";
import {
	clampNumber,
	DEG_TO_RAD,
	IDENTITY_MATRIX,
	normalizeQuat,
	normalizeVec3,
} from "../Tools";
import {
	ICoordinateSystem,
	IEvent,
	IMatrix44,
	INavigationState,
	INavStepFunction,
	IRotationMode,
	ITrackballState,
	IVector2,
	IVector3,
	IVector4,
} from "../Types";
import {
	mat4,
	quat,
	vec2,
	vec3,
	vec4,
} from "gl-matrix";


///////////////////////////////////////////////////////////////////////////////
/**
 * Make the default trackball state.
 * @returns {ITrackballState} The default trackball state.
 */
///////////////////////////////////////////////////////////////////////////////

function makeDefaultTrackballState() : ITrackballState
{
	return {
		center: [ 0, 0, 0 ],
		distance: 0,
		rotation: [ 0, 0, 0, 1 ]
	};
}


///////////////////////////////////////////////////////////////////////////////
/**
 * Viewer event handler that prints the events.
 * @class
 */
///////////////////////////////////////////////////////////////////////////////

export class Trackball extends BaseClass
{
	#matrix: ( IMatrix44 | null ) = null;
	#inverse: ( IMatrix44 | null ) = null;
	#mode: IRotationMode = "turn_table";
	#state: ITrackballState = makeDefaultTrackballState();

	/**
	 * Construct the class.
	 * @class
	 */
	constructor ()
	{
		super();
	}

	/**
	 * Get the class name.
	 * @returns {string} The class name.
	 */
	public override getClassName () : string
	{
		return "Navigators.Trackball";
	}

	/**
	 * Calculate and return the matrix.
	 * @returns {IMatrix44} The view matrix.
	 */
	protected calculateMatrix () : IMatrix44
	{
		// Shortcuts.
		const c = this.#state.center;
		const d = this.#state.distance;
		const r = this.#state.rotation;

		// The matrix that makes the center point the actual center of rotation.
		const tm: IMatrix44 = [ ...IDENTITY_MATRIX ];
		mat4.translate ( tm, IDENTITY_MATRIX, [ -c[0], -c[1], -c[2] ] );

		// Make the rotation matrix.
		const rm: IMatrix44 = [ ...IDENTITY_MATRIX ];
		mat4.fromQuat ( rm, r );

		// The matrix that pushes the model away from the camera.
		const dm: IMatrix44 = [ ...IDENTITY_MATRIX ];
		mat4.translate ( dm, IDENTITY_MATRIX, [ 0, 0, -d ] );

		// Multiply everything together in the correct order.
		const answer: IMatrix44 = [ ...IDENTITY_MATRIX ];
		mat4.multiply ( answer, answer, dm );
		mat4.multiply ( answer, answer, rm );
		mat4.multiply ( answer, answer, tm );

		// Return the answer.
		return answer;
	}

	/**
	 * Get the view matrix.
	 * @returns {IMatrix44} The view matrix.
	 */
	public override get viewMatrix () : Readonly<IMatrix44>
	{
		// Initialize the answer.
		let vm = this.#matrix;

		// If the answer is invalid ...
		if ( !vm )
		{
			// Give it space for the answer.
			vm = [ ...IDENTITY_MATRIX ];

			// Calculate and copy the new matrix.
			mat4.copy ( vm, this.calculateMatrix() );

			// Assign the answer for next time.
			this.#matrix = vm;

			// The inverse is now invalid.
			this.#inverse = null;
		}

		// Return what we have.
		return vm;
	}

	/**
	 * Get the inverse view matrix.
	 * @returns {IMatrix44 | null} The inverse view matrix, or null if it does not exist.
	 */
	public override get invViewMatrix () : ( Readonly<IMatrix44> | null )
	{
		// Initialize the answer.
		let ivm = this.#inverse;

		// If the answer is invalid ...
		if ( !ivm )
		{
			// Give it space for the answer.
			ivm = [ ...IDENTITY_MATRIX ];

			// Calculate the inverse.
			if ( !mat4.invert ( ivm, this.viewMatrix ) )
			{
				// If we get to here then the inverse failed.
				return null;
			}

			// Assign the answer for next time.
			this.#inverse = ivm;
		}

		// Return what we have.
		return ivm;
	}

	/**
	 * Get the rotation mode.
	 * @returns {IRotationMode} The rotation mode.
	 */
	public get mode () : IRotationMode
	{
		return this.#mode;
	}

	/**
	 * Set the rotation mode.
	 * @param {IRotationMode} mode - The rotation mode.
	 */
	public set mode ( mode: IRotationMode )
	{
		this.#mode = mode;
	}

	/**
	 * Get the rotation mode. This is part of the INavigator interface.
	 * @returns {IRotationMode | null} The rotation mode.
	 */
	public get rotationMode () : ( IRotationMode | null )
	{
		return this.mode;
	}

	/**
	 * Get the center point.
	 * @returns {IVector3} The center point.
	 */
	public get center () : Readonly<IVector3>
	{
		return this.#state.center;
	}

	/**
	 * Set the center point.
	 * @param {IVector3} c - The center point.
	 */
	public set center ( c: Readonly<IVector3> )
	{
		vec3.copy ( this.#state.center, c );
		this.#matrix = null;
	}

	/**
	 * Get the distance.
	 * @returns {number} The distance.
	 */
	public get distance () : number
	{
		return this.#state.distance;
	}

	/**
	 * Set the distance.
	 * @param {number} d - The distance.
	 */
	public set distance ( d: number )
	{
		this.#state.distance = d;
		this.#matrix = null;
	}

	/**
	 * Get the rotation.
	 * @returns {IVector4} The rotation.
	 */
	public get rotation () : Readonly<IVector4>
	{
		return this.#state.rotation;
	}

	/**
	 * Set the rotation.
	 * @param {IVector4} r - The rotation.
	 */
	public set rotation ( r: Readonly<IVector4> )
	{
		vec4.copy ( this.#state.rotation, r );
		this.#matrix = null;
	}

	/**
	 * Rotate the navigator.
	 * @param {IVector4} quaternion - The rotation quaternion.
	 */
	public override rotateQuaternion ( quaternion: IVector4 ) : void
	{
		// Make sure it's normalized.
		quaternion = normalizeQuat ( quaternion );

		// Make space for the answer.
		let answer: IVector4 = [ 0, 0, 0, 1 ];

		// This order is rotation about global axes.
		quat.multiply ( answer, quaternion, this.rotation );

		// Make sure it's normalized.
		answer = normalizeQuat ( answer );

		// Set the new rotation.
		this.rotation = answer;
	}

	/**
	 * Rotate the navigator.
	 * @param {IVector3} axis - The rotation axis.
	 * @param {number} radians - The angle in radians.
	 * @param {ICoordinateSystem} space - The rotation space.
	 */
	public override rotateAxisAngle ( axis: IVector3, radians: number, space: ICoordinateSystem ) : void
	{
		// Make sure the axis is normalized.
		axis = normalizeVec3 ( axis );

		// Make space for the rotation.
		let dr: IVector4 = [ 0, 0, 0, 1 ];

		// Calculate the rotation quaternion.
		quat.setAxisAngle ( dr, axis, radians );

		// Normalize the quaternion.
		dr = normalizeQuat ( dr );

		// The new rotation.
		let nr: IVector4 = [ 0, 0, 0, 1 ];

		// Multiply in the correct order.
		switch ( space )
		{
			case "global":
			{
				quat.multiply ( nr, dr, this.rotation );
				break;
			}
			case "local":
			{
				quat.multiply ( nr, this.rotation, dr );
				break;
			}
			default:
			{
				throw new Error ( `Unrecognized coordinate system: ${space as string}` );
			}
		}

		// Make sure it's normalized.
		nr = normalizeQuat ( nr );

		// Set the new rotation.
		this.rotation = nr;
	}

	/**
	 * Translate the navigator.
	 * @param {object} input - The input parameters.
	 * @param {IVector2} input.current - The current screen position.
	 * @param {IVector2} input.previous - The previous screen position.
	 * @param {number} input.scale - The translation scale factor.
	 */
	public override translateScreenXY ( input: { current: IVector2, previous: IVector2, scale: number } ) : void
	{
		// Get the input.
		const { current, previous, scale } = input;

		// The two points make our translation vector.
		const t: IVector2 = [ 0, 0 ];
		vec2.subtract ( t, previous, current );
		vec2.scale ( t, t, scale );

		// Get the center in global space.
		const center: IVector3 = [ ...this.center ];
		vec3.transformMat4 ( center, center, this.viewMatrix );

		// Now translate the center.
		vec3.add ( center, center, [ t[0], t[1], 0 ] );

		// Get the inverse of the view matrix.
		const ivm = this.invViewMatrix;

		// Handle invalid matrix.
		if ( !ivm )
		{
			return;
		}

		// Put the new center point in model space.
		vec3.transformMat4 ( center, center, ivm );

		// Set the new center.
		this.center = center;
	}

	/**
	 * Zoom the navigator.
	 * @param {number} scale - The zoom scale factor.
	 */
	public zoom ( scale: number ) : void
	{
		this.distance *= scale;
		this.#matrix = null;
	}

	/**
	 * Reset the navigator to its default state.
	 */
	public override reset() : void
	{
		this.#state = makeDefaultTrackballState();
		this.#matrix = null;
	}

	/**
	 * Get the internal state.
	 * @returns {INavigationState} The internal state.
	 */
	public override getInternalState() : INavigationState
	{
		const state = this.#state;
		const result: ITrackballState = {
			center: [ ...state.center ],
			distance: state.distance,
			rotation: [ ...state.rotation ],
		};
		return result;
	}

	/**
	 * Set the internal state.
	 * @param {INavigationState} state - The internal state.
	 */
	public override setInternalState ( state: Readonly<INavigationState> ) : void
	{
		const input = ( state as Readonly<ITrackballState> );
		this.center = input.center;
		this.distance = input.distance;
		this.rotation = input.rotation;
	}

	/**
	 * Blend the given navigation states.
	 * @param {INavigationState} from - The starting state.
	 * @param {INavigationState} to - The ending state.
	 * @param {number} fraction - The fraction between the two states.
	 * @returns {INavigationState} The blended state.
	 */
	public override blend ( from: Readonly<INavigationState>, to: Readonly<INavigationState>, fraction: number ) : INavigationState
	{
		const fromState = from as Readonly<ITrackballState>;
		const toState = to as Readonly<ITrackballState>;

		// Lerp the center.
		const center: IVector3 = [ 0, 0, 0 ];
		vec3.lerp ( center, fromState.center, toState.center, fraction );

		// Lerp the distance.
		const distance = ( ( 1 - fraction ) * fromState.distance ) + ( fraction * toState.distance );

		// Slerp the rotation.
		const rotation: IVector4 = [ 0, 0, 0, 1 ];
		quat.slerp ( rotation, fromState.rotation, toState.rotation, fraction );

		// Make and return the result.
		const result: ITrackballState = {
			center,
			distance,
			rotation,
		};
		return result;
	}

	/**
	 * Set the navigator so that the sphere is completely within the view-volume.
	 * @param {object} input - The input parameters.
	 * @param {Sphere} input.sphere - The sphere to view.
	 * @param {Projection} input.projection - The projection to use.
	 * @param {boolean} [input.resetRotation] - Whether to or not reset the rotation.
	 */
	public override viewSphere ( input: { sphere: Sphere, projection: Projection, resetRotation?: boolean } ) : void
	{
		// Get the input.
		const { sphere, projection, resetRotation } = input;

		if ( projection instanceof Perspective )
		{
			const { fov } = projection;
			const { radius } = sphere;

			// Think of a ball falling into a cone. The field-of-view (fov) is the
			// angle of the cone's point. We want the distance from the cone's point
			// to the center of the ball. The radius from the center of the ball to
			// where the ball touches the cone makes a 90 degree angle with the cone.
			// The hypotenuse of the two symmetric triangles is the new trackball
			// distance. The geometry can be calculated in 2D.

			// sin ( theta ) = opposite / hypotenuse
			// hypotenuse = opposite / sin ( theta )
			// theta = fov / 2
			// opposite = radius
			// hypotenuse = radius / sin ( fov / 2 )
			const hypotenuse = radius / ( Math.sin ( ( fov / 2 ) * DEG_TO_RAD ) );

			// The hypotenuse is the new distance.
			this.distance = hypotenuse;

			// Set the center.
			this.center = sphere.center;

			// Reset the rotation if we should.
			if ( resetRotation )
			{
				this.rotation = [ 0, 0, 0, 1 ];
			}
		}

		else
		{
			throw new Error ( `Projection type '${projection.type}' not supported when viewing sphere` );
		}
	}

	/**
	 * Make the trackball sphere.
	 * @param {number} [radius] - The sphere radius.
	 * @returns {Sphere} The trackball sphere.
	 */
	public makeSphere ( radius: ( number | undefined ) = 1 ) : Sphere
	{
		return new Sphere ( [ 0, 0, -2 ], radius );
	}

	/**
	 * Handle the event.
	 * @param {IEvent} event - The event.
	 * @returns {boolean} True if the event was handled, false if not.
	 */
	public override handleEvent ( event: IEvent ) : boolean
	{
		// Shortcut.
		const { viewer } = event;

		// Get the command for this event's input state.
		const command = viewer.getCommand ( event );

		// Handle no command.
		if ( !command )
		{
			return false;
		}

		// If we get to here then execute the command.
		command.execute ( event );

		// We handled the event.
		return true;
	}

	/**
	 * Translate the navigator in screen x-y space.
	 * @param {object} params - The parameters.
	 * @param {IEvent} params.event - The event.
	 * @param {number} params.scale - The translation scale factor.
	 * @returns {INavStepFunction | null} The navigation step function or null.
	 */
	public override mouseTranslate ( params: { event: IEvent, scale: number } ) : ( INavStepFunction | null )
	{
		// Get the input.
		const { event, scale } = params;
		const { previous: pm, current: cm, viewer } = event;

		// Handle no mouse points.
		if ( !pm || !cm )
		{
			return null;
		}

		// Handle zero distance between screen points.
		if ( true === vec2.equals ( cm, pm ) )
		{
			return null;
		}

		// We need the inverse of the view matrix in order to proceed.
		const ivm = this.invViewMatrix;

		// Handle invalid matrix.
		if ( !ivm )
		{
			return null;
		}

		// Get the line under the current mouse point in global space.
		const cl = viewer.makeLine ( { screenPoint: cm, viewMatrix: IDENTITY_MATRIX } );

		// Handle invalid line.
		if ( !cl?.valid )
		{
			return null;
		}

		// Get the line under the previous mouse point in global space.
		const pl = viewer.makeLine ( { screenPoint: pm, viewMatrix: IDENTITY_MATRIX } );

		// Handle invalid line.
		if ( !pl?.valid )
		{
			return null;
		}

		// Make sure the lines are normalized.
		cl.normalize();
		pl.normalize();

		// Make a plane parallel to the view-plane at the negative distance.
		const point: IVector3 = [ 0, 0, -this.distance ];
		const plane = new Plane ( { point, normal: [ 0, 0, 1 ] } );

		// Intersect the lines with the plane.
		const ci = intersectLinePlane ( { line: cl, plane } );
		const pi = intersectLinePlane ( { line: pl, plane } );

		// Handle no intersections.
		if ( ( null === ci ) || ( null === pi ) )
		{
			return null;
		}
		if ( ( false === isFiniteNumber ( ci ) ) || ( false === isFiniteNumber ( pi ) ) )
		{
			return null;
		}

		// Get the intersection points.
		const cp = cl.getPoint ( ci );
		const pp = pl.getPoint ( pi );

		// Make the 2D points.
		const current:  IVector2 = [ cp[0], cp[1] ];
		const previous: IVector2 = [ pp[0], pp[1] ];

		// Make the animation step function.
		const oneStep = ( fraction: number ) =>
		{
			// We want to go from 1 to 0, and keep it in range.
			fraction = clampNumber ( ( 1 - fraction ), 0, 1 );

			// Are we done?
			if ( fraction <= 0 )
			{
				return;
			}

			// It's a little too sensitive without this.
			fraction *= 0.4;

			// Translate the trackball.
			this.translateScreenXY ( { current, previous, scale: ( scale * fraction ) } );
		};

		// Take one step.
		oneStep ( 0 );

		// Return the animation step function.
		return oneStep;
	}

	/**
	 * Rotate the navigator.
	 * @param {object} input - The input parameters.
	 * @param {IEvent} input.event - The event.
	 * @param {number} input.scale - The rotation scale factor.
	 * @returns {INavStepFunction | null} The navigation step function or null.
	 */
	public override mouseRotate ( input: { event: IEvent, scale: number } ) : ( INavStepFunction | null )
	{
		switch ( this.mode )
		{
			case "track_ball":
			{
				return this.trackballRotate ( input );
			}
			case "turn_table":
			{
				return this.turnTableRotate ( input );
			}
			default:
			{
				throw new Error ( "Unknown rotation mode" );
			}
		}
	}

	/**
	 * Rotate the navigator as a trackball.
	 * @param {object} input - The input parameters.
	 * @param {IEvent} input.event - The event.
	 * @param {number} input.scale - The rotation scale factor.
	 * @returns {INavStepFunction | null} The navigation step function or null.
	 */
	public trackballRotate ( input: { event: IEvent, scale: number } ) : ( INavStepFunction | null )
	{
		// Get input.
		const { event, scale } = input;

		// Get the event properties.
		const { current: cm, previous: pm, viewer } = event;

		// Handle invalid input.
		if ( !cm || !pm )
		{
			return null;
		}

		// Handle zero distance between screen points.
		if ( true === vec2.equals ( cm, pm ) )
		{
			return null;
		}

		// Get the line under the current mouse point in global space.
		const cl = viewer.makeLine ( { screenPoint: cm, viewMatrix: [ ...IDENTITY_MATRIX ] } );

		// Handle invalid line.
		if ( !cl?.valid )
		{
			return null;
		}

		// Get the line under the previous mouse point in global space.
		const pl = viewer.makeLine ( { screenPoint: pm, viewMatrix: [ ...IDENTITY_MATRIX ] } );

		// Handle invalid line.
		if ( !pl?.valid )
		{
			return null;
		}

		// Make sure the lines are normalized.
		cl.normalize();
		pl.normalize();

		// Initialize these up here.
		let ci: ILineSphereIntersection = {};
		let pi: ILineSphereIntersection = {};
		const numSteps = 10;
		const minRadius = 1.0;
		let sphere = this.makeSphere ( minRadius );
		let numIntersections = 0;

		// Grow the sphere until we intersect it. We do this because
		// it's a better interaction when intersecting a smaller sphere.
		for ( let i = 1; i < numSteps; ++i )
		{
			// Intersect the lines with the trackball sphere.
			ci = intersectLineSphere ( { line: cl, sphere } );
			pi = intersectLineSphere ( { line: pl, sphere } );

			// If we have four intersections then we're done.
			numIntersections = 0;
			numIntersections += ( isFiniteNumber ( ci.u1 ) ? 1 : 0 );
			numIntersections += ( isFiniteNumber ( ci.u2 ) ? 1 : 0 );
			numIntersections += ( isFiniteNumber ( pi.u1 ) ? 1 : 0 );
			numIntersections += ( isFiniteNumber ( pi.u2 ) ? 1 : 0 );

			// If we have two intersections for each line then we're done.
			// We ignore zero or one (tangent) intersections.
			if ( 4 === numIntersections )
			{
				// console.log ( "Intersecting the trackball sphere took " + i + " steps." );
				break;
			}

			// We want a number that varies from 1.0 to 2.0;
			const radius = ( minRadius + ( i / ( numSteps - 1 ) ) );

			// Make the trackball sphere again, but larger.
			sphere = this.makeSphere ( radius );
		}

		// Handle no intersections.
		// By the time we get to here this should not happen.
		if ( numIntersections !== 4 )
		{
			console.warn ( "No intersections with the trackball sphere" );
			return null;
		}

		// Get the smaller parameter because that is the closest intersection.
		const uc = Math.min ( ci.u1!, ci.u2! );
		const up = Math.min ( pi.u1!, pi.u2! );

		// Get the intersection points.
		const p0: IVector3 = pl.getPoint ( up );
		const p1: IVector3 = cl.getPoint ( uc );

		// Make the vector from the sphere center to the first intersection point.
		let v0: IVector3 = [ 0, 0, 0 ];
		vec3.subtract ( v0, p0, sphere.center );
		v0 = normalizeVec3 ( v0 );

		// Make the vector from the sphere center to the second intersection point.
		let v1: IVector3 = [ 0, 0, 0 ];
		vec3.subtract ( v1, p1, sphere.center );
		v1 = normalizeVec3 ( v1 );

		// The cross product is the axis of rotation.
		let axis: IVector3 = [ 0, 0, 0 ];
		vec3.cross ( axis, v0, v1 );
		axis = normalizeVec3 ( axis );

		// The angle between the two vectors.
		let angle = vec3.angle ( v0, v1 );

		// Multiply by the scale.
		angle *= scale;

		// Handle invalid angles.
		if ( false === isFiniteNumber ( angle ) )
		{
			return null;
		}

		// Make the animation step function.
		const oneStep = ( fraction: number ) =>
		{
			// We want to go from 1 to 0, and keep it in range.
			fraction = clampNumber ( ( 1 - fraction ), 0, 1 );

			// Are we done?
			if ( fraction <= 0 )
			{
				return;
			}

			// Rotate the trackball.
			this.rotateAxisAngle ( axis, ( angle * scale * fraction ), "global" );
		};

		// Take one step.
		oneStep ( 0 );

		// Return the animation step function.
		return oneStep;
	}

	/**
	 * Rotate the navigator as a trackball.
	 * @param {object} input - The input parameters.
	 * @param {IEvent} input.event - The event.
	 * @param {number} input.scale - The rotation scale factor.
	 * @returns {INavStepFunction | null} The navigation step function or null.
	 */
	public turnTableRotate ( input: { event: IEvent, scale: number } ) : ( INavStepFunction | null )
	{
		// Get input.
		const { event, scale } = input;

		// Get the event properties.
		const { current: cm, previous: pm } = event;

		// Handle invalid input.
		if ( !cm || !pm )
		{
			return null;
		}

		// Handle zero distance between screen points.
		if ( true === vec2.equals ( cm, pm ) )
		{
			return null;
		}

		// We need to slow it down.
		const sensitivity = [ 0.1, 0.1 ];

		// Make the animation step function.
		const oneStep = ( fraction: number ) =>
		{
			// We want to go from 1 to 0, and keep it in range.
			fraction = clampNumber ( ( 1 - fraction ), 0, 1 );

			// Are we done?
			if ( fraction <= 0 )
			{
				return;
			}

			// Rotate about the global x-axis.
			{
				// Get the model's current y-axis in global space. The transformation
				// matrix includes translations so we have to operate on points at the
				// origin and end of the y-axis.
				const yAxis: IVector3 = [ 0, 1, 0 ];
				const origin: IVector3 = [ 0, 0, 0 ];
				vec3.transformMat4 ( yAxis, yAxis, this.viewMatrix );
				vec3.transformMat4 ( origin, origin, this.viewMatrix );
				vec3.subtract ( yAxis, yAxis, origin );
				vec3.normalize ( yAxis, yAxis );

				// The vertical mouse distance determines the angle about the global x-axis.
				const angle = ( cm[1] - pm[1] ) * DEG_TO_RAD * sensitivity[0] * scale * fraction;

				// Rotate the y-axis by this angle.
				vec3.rotateX ( yAxis, yAxis, [ 0, 0, 0 ], angle );

				// Make sure this rotation will not "pitch" the model too far.
				if ( yAxis[1] >= 0 )
				{
					// Rotate about the global x-axis.
					this.rotateAxisAngle ( [ 1, 0, 0 ], angle, "global" );
				}
			}

			// Rotate about the local y-axis.
			{
				// The horizontal mouse distance determines the angle about the local y-axis.
				const angle = ( cm[0] - pm[0] ) * DEG_TO_RAD * sensitivity[1] * scale * fraction;

				// Rotate about the local y-axis.
				this.rotateAxisAngle ( [ 0, 1, 0 ], angle, "local" );
			}
		};

		// Take one step.
		oneStep ( 0 );

		// Return the animation step function.
		return oneStep;
	}
}
